const VALID_DISTANCE = 150;
const SHARP_THRESHOLD = 25;

let accum_in = flow.get('accum_in_count') || 0;
let accum_out = flow.get('accum_out_count') || 0;
let pir_in = flow.get('accum_pir_in') || 0;
let pir_out = flow.get('accum_pir_out') || 0;

let sum_ultra_in = flow.get('sum_ultra_in') || 0;
let sum_ultra_out = flow.get('sum_ultra_out') || 0;
let sum_sharp_in = flow.get('sum_sharp_in') || 0;
let sum_sharp_out = flow.get('sum_sharp_out') || 0;

let sum_raw_ultra_in = flow.get('sum_raw_ultra_in') || 0;
let sum_raw_ultra_out = flow.get('sum_raw_ultra_out') || 0;
let sum_raw_sharp_in = flow.get('sum_raw_sharp_in') || 0;
let sum_raw_sharp_out = flow.get('sum_raw_sharp_out') || 0;

let b_temp = msg.payload.board_temp ?? 32.0;

function calculateSharpCM(analog) {
    if (analog < 50) return 30.0;
    let voltage = (analog / 4095.0) * 3.3;
    let cm = 12.08 * Math.pow(voltage, -1.058);
    return (cm > 30) ? 30 : (cm < 4 ? 4 : cm);
}

function usToCm(us, temp) {
    let speed_m_s = 331.3 + (0.606 * temp);
    let speed_cm_us = speed_m_s / 10000;
    return (us * speed_cm_us) / 2;
}

let is_event = false;
let direction = "";

let u_us = msg.payload.ultrasonic_us ?? 0;
let s_raw = msg.payload.sharp_analog ?? 0;

let corrected_ultra = usToCm(u_us, b_temp);
let sharp_cm = calculateSharpCM(s_raw);
let is_counted = 0;

if (msg.topic === 'b6710545768/ParksenseIn' && msg.payload.pir === 1) {
    is_event = true;
    direction = "IN";
    pir_in += 1;
    flow.set('last_board_temp', b_temp);

    if (corrected_ultra > 2 && corrected_ultra <= VALID_DISTANCE) {
        is_counted = 1;
        accum_in += 1;
        sum_ultra_in += corrected_ultra;
        sum_sharp_in += sharp_cm;
        sum_raw_ultra_in += u_us;
        sum_raw_sharp_in += s_raw;
    } else {
        node.warn("IN: False Positive ดรอปทิ้ง");
    }

}
else if (msg.topic === 'b6710545768/ParksenseOut' && msg.payload.pir === 1) {
    is_event = true;
    direction = "OUT";
    pir_out += 1;
    flow.set('last_board_temp', b_temp);

    if (corrected_ultra > 2 && corrected_ultra <= VALID_DISTANCE) {
        is_counted = 1;
        accum_out += 1;
        sum_ultra_out += corrected_ultra;
        sum_sharp_out += sharp_cm;
        sum_raw_ultra_out += u_us;
        sum_raw_sharp_out += s_raw;
    } else {
        node.warn("OUT: False Positive ดรอปทิ้ง");
    }
}

flow.set('accum_in_count', accum_in);
flow.set('accum_out_count', accum_out);
flow.set('accum_pir_in', pir_in);
flow.set('accum_pir_out', pir_out);

flow.set('sum_ultra_in', sum_ultra_in);
flow.set('sum_ultra_out', sum_ultra_out);
flow.set('sum_sharp_in', sum_sharp_in);
flow.set('sum_sharp_out', sum_sharp_out);

flow.set('sum_raw_ultra_in', sum_raw_ultra_in);
flow.set('sum_raw_ultra_out', sum_raw_ultra_out);
flow.set('sum_raw_sharp_in', sum_raw_sharp_in);
flow.set('sum_raw_sharp_out', sum_raw_sharp_out);

if (is_event) {
    let sql = `INSERT INTO parking_events 
    (direction, raw_ultrasonic_us, ultrasonic_cm, raw_sharp_analog, sharp_cm, board_temp, is_counted) 
    VALUES 
    ('${direction}', ${u_us}, ${corrected_ultra.toFixed(2)}, ${s_raw}, ${sharp_cm.toFixed(2)}, ${b_temp}, ${is_counted});`;

    msg.topic = sql;
    return msg;
}

return null;

let w = msg.payload;

const MAX_CAPACITY = 222; 
const START_COUNT = 23; 

let api_temp = (w && w.main) ? w.main.temp : 32.0;
let api_feels_like = (w && w.main) ? w.main.feels_like : 32.0;
let api_humidity = (w && w.main) ? w.main.humidity : 60;
let api_clouds = (w && w.clouds) ? w.clouds.all : 0;
let is_raining = (w && w.weather && w.weather.length > 0 && w.weather[0].id < 600) ? 1 : 0;

let in_count = flow.get('accum_in_count') || 0;
let out_count = flow.get('accum_out_count') || 0;
let net_flow = in_count - out_count;

let board_temperature = flow.get('last_board_temp') || 0.0;

let avg_ultra_in = (in_count > 0) ? (flow.get('sum_ultra_in') / in_count).toFixed(2) : "0.00";
let avg_sharp_in = (in_count > 0) ? (flow.get('sum_sharp_in') / in_count).toFixed(2) : "0.00";
let avg_ultra_out = (out_count > 0) ? (flow.get('sum_ultra_out') / out_count).toFixed(2) : "0.00";
let avg_sharp_out = (out_count > 0) ? (flow.get('sum_sharp_out') / out_count).toFixed(2) : "0.00";

let avg_raw_ultra_in = (in_count > 0) ? (flow.get('sum_raw_ultra_in') / in_count).toFixed(0) : "0";
let avg_raw_sharp_in = (in_count > 0) ? (flow.get('sum_raw_sharp_in') / in_count).toFixed(0) : "0";
let avg_raw_ultra_out = (out_count > 0) ? (flow.get('sum_raw_ultra_out') / out_count).toFixed(0) : "0";
let avg_raw_sharp_out = (out_count > 0) ? (flow.get('sum_raw_sharp_out') / out_count).toFixed(0) : "0";

let current_vehicles = flow.get('global_vehicles');
if (current_vehicles === undefined) current_vehicles = START_COUNT;

current_vehicles += net_flow;
if (current_vehicles < 0) {
    current_vehicles = 0;
    out_count = in_count; 
    net_flow = 0;
} else if (current_vehicles > MAX_CAPACITY) {
    current_vehicles = MAX_CAPACITY;
    in_count = out_count; 
    net_flow = 0;
}
flow.set('global_vehicles', current_vehicles);

let parking_percentage = parseFloat(((current_vehicles / MAX_CAPACITY) * 100).toFixed(2));

let sql = `INSERT INTO parking_logs 
(timestamp, in_count, out_count, net_flow, current_vehicles, parking_percentage, 
api_temperature, api_feels_like, api_humidity, api_clouds, board_temperature, is_raining, 
pir_in_trigger, raw_ultrasonic_in_us, ultrasonic_in_cm, raw_lidar_in_analog, lidar_in_cm, 
pir_out_trigger, raw_ultrasonic_out_us, ultrasonic_out_cm, raw_lidar_out_analog, lidar_out_cm) 
VALUES 
(NOW(), ${in_count}, ${out_count}, ${net_flow}, ${current_vehicles}, ${parking_percentage}, 
${api_temp}, ${api_feels_like}, ${api_humidity}, ${api_clouds}, ${board_temperature}, ${is_raining}, 
${flow.get('accum_pir_in') || 0}, ${avg_raw_ultra_in}, ${avg_ultra_in}, ${avg_raw_sharp_in}, ${avg_sharp_in}, 
${flow.get('accum_pir_out') || 0}, ${avg_raw_ultra_out}, ${avg_ultra_out}, ${avg_raw_sharp_out}, ${avg_sharp_out});`;

msg.topic = sql;

flow.set('accum_in_count', 0);
flow.set('accum_out_count', 0);
flow.set('accum_pir_in', 0);
flow.set('accum_pir_out', 0);

flow.set('sum_ultra_in', 0);
flow.set('sum_ultra_out', 0);
flow.set('sum_sharp_in', 0);
flow.set('sum_sharp_out', 0);

flow.set('sum_raw_ultra_in', 0);
flow.set('sum_raw_ultra_out', 0);
flow.set('sum_raw_sharp_in', 0);
flow.set('sum_raw_sharp_out', 0);

return msg;
